use std::fmt;
use std::error::Error;

#[derive(Debug)]
struct SensorError(String);

impl fmt::Display for SensorError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Data validation failed: {}", self.0)
    }
}

impl Error for SensorError {}

#[derive(Debug)]
struct InputParsingError(String);

impl fmt::Display for InputParsingError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Input format issue: {}", self.0)
    }
}

impl Error for InputParsingError {}

fn process_sensor_data(raw_readings: &[&str]) -> Result<Vec<f64>, Box<dyn Error>> {
    let mut processed_values = Vec::new();
    for (i, &reading) in raw_readings.iter().enumerate() {
        match reading.parse::<f64>() {
            Ok(val) => processed_values.push(val),
            Err(_) => return Err(Box::new(SensorError(format!("Could not parse data point at index {}: '{}'", i, reading))))
        }
    }
    Ok(processed_values)
}

fn main() {
    let good_data = vec!["10.5", "22.1", "30.0"];
    match process_sensor_data(&good_data) {
        Ok(data) => println!("Successfully processed data: {:?}", data),
        Err(e) => eprintln!("Error processing good data: {}", e),
    }

    let bad_data = vec!["5.0", "invalid_reading", "15.2"];
    match process_sensor_data(&bad_data) {
        Ok(data) => println!("Successfully processed data: {:?}", data),
        Err(e) => eprintln!("Caught expected error for bad data: {}", e),
    }
}

use std::fmt::{self, Display};
use std::fs::File;
use std::io::{self, Read};
use std::path::Path;

#[derive(Debug)]
enum AppError {
    Io(io::Error),
    Parse(&'static str),
}

impl From<io::Error> for AppError {
    fn from(err: io::Error) -> Self {
        AppError::Io(err)
    }
}

impl Display for AppError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            AppError::Io(err) => write!(f, "I/O Error: {}", err),
            AppError::Parse(msg) => write!(f, "Parsing failed: {}", msg),
        }
    }
}

impl std::error::Error for AppError {}

fn process_file_data(path: &Path) -> Result<String, AppError> {
    let mut file = File::open(path)?;
    let mut buffer = String::new();
    file.read_to_string(&mut buffer)?;
    Ok(buffer)
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let temp_path = Path::new("test_data.txt");
    if !temp_path.exists() {
        std::fs::write(temp_path, "Some test content.")?;
    }

    match process_file_data(temp_path) {
        Ok(data) => println!("Successfully processed data: {}", data),
        Err(e) => eprintln!("Caught application error: {}", e),
    }

    std::fs::remove_file(temp_path)?;
    Ok(())
}

